import{_ as t,o as a,c as r,ae as i}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Data Integration Steps for Developers","description":"","frontmatter":{"title":"Data Integration Steps for Developers","slug":"data-integration-steps-for-developers"},"headers":[],"relativePath":"developer-hub/data-integration-steps-for-developers.md","filePath":"developer-hub/data-integration-steps-for-developers.md"}'),d={name:"developer-hub/data-integration-steps-for-developers.md"};function o(n,e,s,l,h,c){return a(),r("div",null,[...e[0]||(e[0]=[i('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Data Integrations provide an easy way to automatically send Branch data to your other analytics services and marketing tools using pre-formatted webhooks.</p><p>This guide covers the technical implementation requirements for Data Integrations. For setup instructions in Branch, see our <a href="./data-integration-implementation-guide.html">Data Integrations guide in Marketer Hub</a>.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to use Branch Data Integrations, you must first:</p><ol><li><a href="./native-sdks-overview.html">Implement the Branch SDK</a></li><li><a href="./track-branch-events.html">Ensure app events are measured</a></li><li>Be a customer to the third party and have their respective SDK installed in your app.</li></ol><h2 id="pass-id-metadata-to-branch-partner-specific" tabindex="-1">Pass ID/metadata to Branch (partner specific) <a class="header-anchor" href="#pass-id-metadata-to-branch-partner-specific" aria-label="Permalink to &quot;Pass ID/metadata to Branch (partner specific)&quot;">​</a></h2><p>For some partners, you&#39;ll need to make sure to pass through the correct identifiers to the Branch SDKs. In order to do so, retrieve the ID from the partner SDK and pass this value to Branch using the following method:<br><code>setRequestMetadataKey()</code> method of the Branch SDKs: <a href="./ios-advanced-features.html#section-set-initialization-metadata">iOS</a> | <a href="./android-advanced-features.html#section-set-initialization-metadata">Android</a></p><details><summary>FIND PARTNER KEY &amp; METHOD TO PASS TO BRANCH</summary><table tabindex="0"><thead><tr><th>Data Integration Partner</th><th>Partner Key &amp; Method to pass to Branch SDK</th></tr></thead><tbody><tr><td>Adobe Analytics</td><td>- <a href="https://help.branch.io/partners-portal/docs/adobe-analytics?highlight=adobe%20analytics" target="_blank" rel="noreferrer">View Adobe Analytics (Data Connector) Specific Guide Here</a></td></tr><tr><td>Adobe Analytics</td><td>- <a href="./adobe-analytics.html">View Adobe Analytics (Processing Rules) Specific Guide Here</a></td></tr><tr><td>Airship</td><td>- <a href="./airship.html">View Airship Specific Guide Here</a></td></tr><tr><td>Amplitude</td><td>- Set value for $amplitude_device_id &amp; $amplitude_user_id keys using setRequestMetadataKey() method</td></tr><tr><td>Batch</td><td>- <a href="./batch.html">View Batch Specific Guide Here</a></td></tr><tr><td>Braze</td><td>- <a href="./braze.html">View Braze Specific Guide Here</a></td></tr><tr><td>CleverTap</td><td>- <a href="./clevertap.html">View CleverTap Specific Guide Here</a></td></tr><tr><td>Google Analytics</td><td>- <a href="./google-analytics.html">View Google Analytics Specific Guide Here</a></td></tr><tr><td>Google Analytics 4</td><td>- <a href="./google-analytics-4-configuration.html">View Google Analytics 4 Specific Guide Here</a></td></tr><tr><td>Google Firebase</td><td>- <a href="./firebase.html">View Google Firebase Specific Guide Here</a></td></tr><tr><td>Iterable</td><td>- Set Iterable user ID using setIdentity() method</td></tr><tr><td>Mixpanel</td><td>- <a href="./mixpanel.html">View Mixpanel Specific Guide Here</a></td></tr><tr><td>MoEngage</td><td>- <a href="./moengage.html">View MoEngage Specific Guide Here</a></td></tr><tr><td>Movable Ink</td><td>- <a href="./movable-ink.html">View Movable Ink Specific Guide Here</a></td></tr><tr><td>mParticle</td><td>- <a href="./mparticle-import.html">View mParticle Import Specific Guide Here</a></td></tr><tr><td>mParticle</td><td>- <a href="./mparticle.html">View mParticle Export Specific Guide Here</a></td></tr><tr><td>Segment</td><td>- <a href="./segment-import.html">View Segment Import Specific Guide Here</a></td></tr><tr><td>Segment</td><td>- <a href="./segment-export.html">View Segment Export Specific Guide Here</a></td></tr></tbody></table></details><h2 id="additional-steps-for-data-integrations" tabindex="-1">Additional steps for Data Integrations <a class="header-anchor" href="#additional-steps-for-data-integrations" aria-label="Permalink to &quot;Additional steps for Data Integrations&quot;">​</a></h2><p>To learn more about setting up Data Integrations, visit our <a href="./data-integration-implementation-guide.html">Data Integrations guide</a>.</p>',11)])])}const u=t(d,[["render",o]]);export{m as __pageData,u as default};
